query:
SELECT COUNT(*) as total, MIN(comissao) as min_c, MAX(comissao) as max_c, AVG(comissao) as avg_c FROM pro_rata;
SELECT COUNT(*) as registros_abaixo_1 FROM pro_rata WHERE comissao < 1;
SELECT COUNT(*) as registros_entre_1_e_10 FROM pro_rata WHERE comissao >= 1 AND comissao <= 10;
SELECT COUNT(*) as registros_acima_10 FROM pro_rata WHERE comissao > 10;

